query PatientWithObservations($id: ID!) {
  Patient(id: $id) {
    id
    name { given family }
    birthDate
    ObservationList(_reference: subject, code: "85354-9") {
      id
      effectiveDateTime
      component {
        code { coding { code display } }
        valueQuantity { value unit }
      }
    }
  }
}
